if (! function_exists('sqlite_backup')) {
    function sqlite_backup($database = null, $mode = null, $tables = null, $output = null, $timeout = null)
    {
        $database = isset($database) ? (string)$database : 'rss_archive.sqlite';
        $mode = isset($mode) ? (string)$mode : 'sql';
        $tables = isset($tables) ? (string)$tables : '';
        $output = isset($output) ? (string)$output : '';
        $timeout = isset($timeout) ? max(5, min(30, (int)$timeout)) : 15;

        $valid_modes = ['sql', 'csv', 'schema', 'tables'];
        if (!in_array($mode, $valid_modes)) return ['error' => "Invalid mode: '$mode'. Use: " . implode(', ', $valid_modes), 'success' => false];

        $ws = realpath(__DIR__ . '/../workspace');
        if (!$ws) return ['error' => 'Workspace not found.', 'success' => false];

        $db_path = $ws . '/' . ltrim($database, '/\\');
        if (!file_exists($db_path)) return ['error' => "Database not found: $database", 'success' => false];
        if (!extension_loaded('pdo_sqlite')) return ['error' => 'PDO SQLite extension not available.', 'success' => false];

        $start = microtime(true);

        try {
            $pdo = new PDO('sqlite:' . $db_path, null, null, [
                PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
                PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
            ]);
            
            $deadline = time() + $timeout;
            
            // Get all tables
            $tables_info = [];
            $stmt = $pdo->query("SELECT name, type, sql FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%' ORDER BY name");
            $all_tables = $stmt->fetchAll();
            
            if (empty($all_tables)) return ['error' => 'No user tables found in database.', 'success' => false];
            
            // Filter tables if specified
            $filter_tables = [];
            if (!empty($tables)) {
                $filter_tables = array_map('trim', explode(',', $tables));
            }
            
            // Tables mode - just list tables
            if ($mode === 'tables') {
                $result = [];
                foreach ($all_tables as $t) {
                    if (!empty($filter_tables) && !in_array($t['name'], $filter_tables)) continue;
                    $count = $pdo->query("SELECT COUNT(*) as c FROM \"" . $t['name'] . "\"")->fetch();
                    $result[] = ['name' => $t['name'], 'type' => $t['type'], 'row_count' => (int)$count['c'], 'has_schema' => !empty($t['sql'])];
                }
                return ['success' => true, 'mode' => 'tables', 'database' => $database, 'table_count' => count($result), 'tables' => $result, 'time_ms' => round((microtime(true)-$start)*1000, 1)];
            }
            
            // Schema mode
            if ($mode === 'schema') {
                $sql = "-- SQLite Schema Dump\n";
                $sql .= "-- Database: " . basename($db_path) . "\n";
                $sql .= "-- Generated: " . date('Y-m-d H:i:s') . "\n\n";
                $sql .= "PRAGMA foreign_keys=OFF;\n";
                
                foreach ($all_tables as $t) {
                    if (!empty($filter_tables) && !in_array($t['name'], $filter_tables)) continue;
                    if (!empty($t['sql'])) {
                        $sql .= $t['sql'] . ";\n\n";
                    }
                }
                
                // Get indexes
                $indexes = $pdo->query("SELECT name, sql FROM sqlite_master WHERE type='index' AND sql IS NOT NULL AND name NOT LIKE 'sqlite_%'")->fetchAll();
                foreach ($indexes as $idx) {
                    $sql .= $idx['sql'] . ";\n";
                }
                
                if (!empty($output)) {
                    $out_path = $ws . '/' . $output;
                    file_put_contents($out_path, $sql);
                    return ['success' => true, 'mode' => 'schema', 'database' => $database, 'tables' => count($all_tables), 'output' => $output, 'size' => strlen($sql), 'time_ms' => round((microtime(true)-$start)*1000, 1)];
                }
                
                return ['success' => true, 'mode' => 'schema', 'database' => $database, 'tables' => count($all_tables), 'size' => strlen($sql), 'sql' => $sql, 'time_ms' => round((microtime(true)-$start)*1000, 1)];
            }
            
            // CSV mode
            if ($mode === 'csv') {
                $results = [];
                $errors = [];
                foreach ($all_tables as $t) {
                    if (!empty($filter_tables) && !in_array($t['name'], $filter_tables)) continue;
                    if (time() > $deadline) { $results[] = ['table' => $t['name'], 'status' => 'timed_out']; break; }
                    try {
                        $table_name = $t['name'];
                        $data = $pdo->query("SELECT * FROM \"" . $table_name . "\"")->fetchAll();
                        if (empty($data)) { $results[] = ['table' => $table_name, 'status' => 'empty', 'rows' => 0]; continue; }
                        $columns = array_keys($data[0]);
                        $csv_lines = [implode(',', array_map(function($c) { return '"' . str_replace('"', '""', $c) . '"'; }, $columns))];
                        foreach ($data as $row) {
                            $vals = [];
                            foreach ($columns as $col) {
                                $v = isset($row[$col]) ? (string)$row[$col] : '';
                                $vals[] = '"' . str_replace('"', '""', $v) . '"';
                            }
                            $csv_lines[] = implode(',', $vals);
                        }
                        $csv_content = implode("\n", $csv_lines);
                        $csv_file = $table_name . '_export.csv';
                        file_put_contents($ws . '/' . $csv_file, $csv_content);
                        $results[] = ['table' => $table_name, 'status' => 'exported', 'rows' => count($data), 'file' => $csv_file, 'size' => strlen($csv_content)];
                    } catch (\Throwable $e) {
                        $errors[] = ['table' => $t['name'], 'error' => $e->getMessage()];
                    }
                }
                return ['success' => true, 'mode' => 'csv', 'database' => $database, 'exported' => count($results), 'tables' => $results, 'errors' => $errors ?: null, 'time_ms' => round((microtime(true)-$start)*1000, 1)];
            }
            
            // SQL dump mode
            $sql = "-- SQLite Database Dump\n";
            $sql .= "-- Database: " . basename($db_path) . "\n";
            $sql .= "-- Generated: " . date('Y-m-d H:i:s') . "\n\n";
            $sql .= "PRAGMA foreign_keys=OFF;\nBEGIN TRANSACTION;\n\n";
            
            foreach ($all_tables as $t) {
                if (!empty($filter_tables) && !in_array($t['name'], $filter_tables)) continue;
                if (time() > $deadline) { $sql .= "-- TIMEOUT: export stopped at table " . $t['name'] . "\n"; break; }
                
                $table_name = $t['name'];
                
                // CREATE TABLE
                if (!empty($t['sql'])) {
                    $sql .= $t['sql'] . ";\n\n";
                }
                
                // INSERT data
                $data = $pdo->query("SELECT * FROM \"" . $table_name . "\"")->fetchAll();
                if (!empty($data)) {
                    $columns = array_keys($data[0]);
                    $col_list = '"' . implode('","', $columns) . '"';
                    
                    foreach ($data as $row) {
                        $vals = [];
                        foreach ($columns as $col) {
                            $v = $row[$col];
                            if ($v === null) $vals[] = 'NULL';
                            elseif (is_numeric($v)) $vals[] = $v;
                            else $vals[] = "'" . str_replace("'", "''", (string)$v) . "'";
                        }
                        $sql .= "INSERT INTO \"" . $table_name . "\" (" . $col_list . ") VALUES (" . implode(',', $vals) . ");\n";
                    }
                    $sql .= "\n";
                }
            }
            
            // Get indexes
            $indexes = $pdo->query("SELECT name, sql FROM sqlite_master WHERE type='index' AND sql IS NOT NULL AND name NOT LIKE 'sqlite_%'")->fetchAll();
            foreach ($indexes as $idx) {
                $sql .= $idx['sql'] . ";\n";
            }
            
            $sql .= "COMMIT;\nPRAGMA foreign_keys=ON;\n";
            
            if (!empty($output)) {
                $out_path = $ws . '/' . $output;
                file_put_contents($out_path, $sql);
                $size = strlen($sql);
                return ['success' => true, 'mode' => 'sql', 'database' => $database, 'output' => $output, 'size' => $size, 'time_ms' => round((microtime(true)-$start)*1000, 1)];
            }
            
            return ['success' => true, 'mode' => 'sql', 'database' => $database, 'size' => strlen($sql), 'lines' => substr_count($sql, "\n"), 'dump' => $sql, 'time_ms' => round((microtime(true)-$start)*1000, 1)];
            
        } catch (\Throwable $e) {
            return ['error' => 'Database backup failed: ' . $e->getMessage(), 'success' => false];
        }
    }
}
